import{_ as t}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as d,c as s,a2 as i}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"自動タグ付け","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/Other/auto-tagging.md","filePath":"ja-JP/Other/auto-tagging.md","lastUpdated":1781962217000}'),l={name:"ja-JP/Other/auto-tagging.md"};function n(o,a,c,p,r,h){return d(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="自動タグ付け" tabindex="-1">自動タグ付け <a class="header-anchor" href="#自動タグ付け" aria-label="Permalink to &quot;自動タグ付け&quot;">​</a></h1><p>自動タグ付けは次の場所で設定します。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>システム設定 -&gt; その他の設定 -&gt; 自動タグ付け</span></span></code></pre></div><p>画像にタグを自動で付け、検索、ランダム画像 API、公開ギャラリー、年齢レーティングによるアクセス制御で使いやすくします。</p><h2 id="できること" tabindex="-1">できること <a class="header-anchor" href="#できること" aria-label="Permalink to &quot;できること&quot;">​</a></h2><table tabindex="0"><thead><tr><th>機能</th><th>説明</th></tr></thead><tbody><tr><td>コンテンツタグ</td><td>人物、背景、物、画風などのタグを付けます</td></tr><tr><td>キャラクタータグ</td><td>アニメ画像やイラストのキャラクター判定に使えます</td></tr><tr><td>向きタグ</td><td><code>landscape</code>、<code>portrait</code>、<code>square</code> を補完します</td></tr><tr><td>画像レーティング</td><td><code>G/S/Q/E</code> の判定結果を保存します</td></tr><tr><td>アップロード時の自動処理</td><td>新規画像をアップロード後に自動で処理します</td></tr><tr><td>一括処理</td><td>既存画像にまとめてタグを付けます</td></tr></tbody></table><h2 id="事前準備" tabindex="-1">事前準備 <a class="header-anchor" href="#事前準備" aria-label="Permalink to &quot;事前準備&quot;">​</a></h2><p>少なくとも 1 つ、アクセス可能な Hugging Face Space URL が必要です。</p><p>おすすめは SmilingWolf の <code>wd-tagger</code> Space を自分の Hugging Face アカウントへ複製する方法です。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>公開 Space をそのまま使うこともできますが、他の利用者と共有されるため、待ち時間が長くなったり一時的に使えなかったりします。長く使うなら、自分のアカウントに複製した Space の方が安定します。</p><h2 id="space-を複製する" tabindex="-1">Space を複製する <a class="header-anchor" href="#space-を複製する" aria-label="Permalink to &quot;Space を複製する&quot;">​</a></h2><ol><li>Hugging Face にログインします。</li><li><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code> を開きます。</li></ol><p><img src="'+t+`" alt="SmilingWolf の公開 Space" loading="lazy"></p><ol start="3"><li>右上のメニューから <code>Duplicate this Space</code> を選びます。</li><li>Space 名を確認します。必要なら <code>wd-tagger</code> など分かりやすい名前にします。</li><li>公開範囲は <code>Public</code> のままにします。</li><li>まずは無料ハードウェアで作成します。</li><li>ビルド完了を待ちます。</li></ol><p>作成後、ブラウザの URL を ImgBed の <code>Space URLs</code> に貼り付けます。</p><h2 id="設定項目" tabindex="-1">設定項目 <a class="header-anchor" href="#設定項目" aria-label="Permalink to &quot;設定項目&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>おすすめ</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>用意した Space URL を 1 行に 1 つ入力</td></tr><tr><td>対象フォルダ</td><td>全体を処理するなら空欄、特定フォルダだけなら選択</td></tr><tr><td>認識モデル</td><td>まずは <code>wd-swinv2-tagger-v3</code></td></tr><tr><td>一般タグしきい値</td><td>迷ったら <code>0.35</code> 前後</td></tr><tr><td>キャラクタータグしきい値</td><td>誤判定を抑えるなら <code>0.85</code> 前後</td></tr><tr><td><code>MCut</code></td><td>最初はオフで試す</td></tr><tr><td>アップロード時自動タグ付け</td><td>新規画像にも使いたい場合だけオン</td></tr></tbody></table><p>タグが多すぎる場合は一般タグしきい値を少し上げます。少なすぎる場合は少し下げます。</p><h2 id="一括タグ付け" tabindex="-1">一括タグ付け <a class="header-anchor" href="#一括タグ付け" aria-label="Permalink to &quot;一括タグ付け&quot;">​</a></h2><ol><li><code>Space URLs</code> を入力します。</li><li>対象フォルダを選びます。</li><li>タグ付けを開始します。</li><li>進行状況が完了するまで待ちます。</li></ol><p>対象フォルダを空にすると、全フォルダが処理対象になります。</p><h2 id="アップロード時の自動処理" tabindex="-1">アップロード時の自動処理 <a class="header-anchor" href="#アップロード時の自動処理" aria-label="Permalink to &quot;アップロード時の自動処理&quot;">​</a></h2><p>有効にすると、新しくアップロードされた画像が自動でタグ付けキューに入ります。</p><p>Space が混雑していても、アップロード自体は先に完了し、タグ付けは後から進みます。</p><h2 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h2><h3 id="なぜ自分の-space-を複製するのですか" tabindex="-1">なぜ自分の Space を複製するのですか？ <a class="header-anchor" href="#なぜ自分の-space-を複製するのですか" aria-label="Permalink to &quot;なぜ自分の Space を複製するのですか？&quot;">​</a></h3><p>公開 Space は多くのユーザーが使います。自分用の Space なら待ち時間が短く、長期運用でも安定しやすくなります。</p><h3 id="タグが英語になるのは正常ですか" tabindex="-1">タグが英語になるのは正常ですか？ <a class="header-anchor" href="#タグが英語になるのは正常ですか" aria-label="Permalink to &quot;タグが英語になるのは正常ですか？&quot;">​</a></h3><p>正常です。SmilingWolf 系モデルは英語タグを返します。検索、フィルタ、ランダム画像 API で使うため、そのまま保存されます。</p><h3 id="レーティングは何に使いますか" tabindex="-1">レーティングは何に使いますか？ <a class="header-anchor" href="#レーティングは何に使いますか" aria-label="Permalink to &quot;レーティングは何に使いますか？&quot;">​</a></h3><p>セキュリティ設定のアクセスモードと組み合わせ、訪問者に公開する画像を年齢レーティングで制御します。</p><h2 id="クイック手順" tabindex="-1">クイック手順 <a class="header-anchor" href="#クイック手順" aria-label="Permalink to &quot;クイック手順&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hugging Face にログイン</span></span>
<span class="line"><span>-&gt; SmilingWolf/wd-tagger を開く</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; ビルド完了を待つ</span></span>
<span class="line"><span>-&gt; Space URL をコピー</span></span>
<span class="line"><span>-&gt; ImgBed の Space URLs に貼り付け</span></span>
<span class="line"><span>-&gt; モデルとしきい値を設定</span></span>
<span class="line"><span>-&gt; 一括タグ付け、またはアップロード時自動タグ付けを有効化</span></span></code></pre></div>`,34)])])}const m=e(l,[["render",n]]);export{b as __pageData,m as default};
